def est_connexe(graphe):
    # On choisit un nœud de départ arbitraire : le premier du dictionnaire
    depart = next(iter(graphe))
    # "visites" est un set (pas une liste) : on n'a besoin que de tester
    # l'appartenance, pas de conserver l'ordre de visite
    visites = {depart}
    file = [depart]
    while file:
        noeud = file.pop(0)
        for voisin in graphe[noeud]:
            if voisin not in visites:
                visites.add(voisin)
                file.append(voisin)
    # Le graphe est connexe si on a réussi à atteindre TOUS ses nœuds
    # depuis un seul point de départ
    return len(visites) == len(graphe)
